// Rise 6.0 - ClientSpoofer (spoofs C15 settings):
// Vanilla C15 is cancelled and replaced with spoofed values
@EventTarget
public void onPacketSend(PacketSendEvent event) {
    if (event.getPacket() instanceof C15PacketClientSettings) {
        event.setCancelled(true);
        // Send spoofed settings: en_US locale, 8 chunk distance
        mc.thePlayer.sendQueue.addToSendQueue(
            new C15PacketClientSettings(
                "en_US",     // locale
                8,            // view distance
                0,            // chat visibility (full)
                true,         // chat colors
                -1,           // difficulty (-1 = unchanged)
                true          // show cape
            ));
    }
}

