package net.minecraft.network.play.client;

import net.minecraft.network.Packet;
import net.minecraft.network.PacketBuffer;
import net.minecraft.network.play.INetHandlerPlayServer;
import java.io.IOException;

public class C15PacketClientSettings implements Packet<INetHandlerPlayServer> {
    private String lang;
    private int view;
    private int chatVisibility;
    private boolean enableColors;
    private int difficulty;
    private boolean showCape;

    public C15PacketClientSettings() {}
    public C15PacketClientSettings(String langIn, int viewIn, int chatVisIn,
                                    boolean colorsIn, int diffIn, boolean capeIn) {
        this.lang = langIn;
        this.view = viewIn;
        this.chatVisibility = chatVisIn;
        this.enableColors = colorsIn;
        this.difficulty = diffIn;
        this.showCape = capeIn;
    }

    public void readPacketData(PacketBuffer buf) throws IOException {
        this.lang = buf.readStringFromBuffer(16);
        this.view = buf.readByte();
        this.chatVisibility = buf.readByte();
        this.enableColors = buf.readBoolean();
        this.difficulty = buf.readByte();
        this.showCape = buf.readBoolean();
    }

    public void processPacket(INetHandlerPlayServer handler) {
        handler.processClientSettings(this);
    }

    public String getLang() { return this.lang; }
    public int getView() { return this.view; }
    public int getChatVisibility() { return this.chatVisibility; }
    public boolean isColorsEnabled() { return this.enableColors; }
    public int getDifficulty() { return this.difficulty; }
    public boolean isShowCape() { return this.showCape; }
}

